#[cfg(test)]
mod tests {
    use super::*;
    use crate::support::{CastFrom, CastInto, Float};

    // Tests against N3220
    fn spec_test<F: Float>(f: impl Fn(F, i32) -> F)
    where
        u32: CastInto<F::Int>,
        F::Int: CastFrom<i32>,
        F::Int: CastFrom<u32>,
    {
        // `scalbn(±0, n)` returns `±0`.
        assert_biteq!(f(F::NEG_ZERO, 10), F::NEG_ZERO);
        assert_biteq!(f(F::NEG_ZERO, 0), F::NEG_ZERO);
        assert_biteq!(f(F::NEG_ZERO, -10), F::NEG_ZERO);
        assert_biteq!(f(F::ZERO, 10), F::ZERO);
        assert_biteq!(f(F::ZERO, 0), F::ZERO);
        assert_biteq!(f(F::ZERO, -10), F::ZERO);

        // `scalbn(x, 0)` returns `x`.
        assert_biteq!(f(F::MIN, 0), F::MIN);
        assert_biteq!(f(F::MAX, 0), F::MAX);
        assert_biteq!(f(F::INFINITY, 0), F::INFINITY);
        assert_biteq!(f(F::NEG_INFINITY, 0), F::NEG_INFINITY);
        assert_biteq!(f(F::ZERO, 0), F::ZERO);
        assert_biteq!(f(F::NEG_ZERO, 0), F::NEG_ZERO);

        // `scalbn(±∞, n)` returns `±∞`.
        assert_biteq!(f(F::INFINITY, 10), F::INFINITY);
        assert_biteq!(f(F::INFINITY, -10), F::INFINITY);
        assert_biteq!(f(F::NEG_INFINITY, 10), F::NEG_INFINITY);
        assert_biteq!(f(F::NEG_INFINITY, -10), F::NEG_INFINITY);

        // NaN should remain NaNs.
        assert!(f(F::NAN, 10).is_nan());
        assert!(f(F::NAN, 0).is_nan());
        assert!(f(F::NAN, -10).is_nan());
        assert!(f(-F::NAN, 10).is_nan());
        assert!(f(-F::NAN, 0).is_nan());
        assert!(f(-F::NAN, -10).is_nan());
    }

    #[test]
    #[cfg(f16_enabled)]
    fn spec_test_f16() {
        spec_test::<f16>(scalbnf16);
    }

    #[test]
    fn spec_test_f32() {
        spec_test::<f32>(scalbnf);
    }

    #[test]
    fn spec_test_f64() {
        spec_test::<f64>(scalbn);
    }

    #[test]
    #[cfg(f128_enabled)]
    fn spec_test_f128() {
        spec_test::<f128>(scalbnf128);
    }
}

use std::collections::HashMap;
use std::ffi::OsStr;
use std::path::Path;
use std::process::Command;

pub fn write_file(file_path: impl AsRef<Path>, content: &str) -> Result<(), String> {
    std::fs::write(&file_path, content).map_err(|error| {
        format!(
            "Failed to create empty `{}` file: {error:?}",
            file_path.as_ref().display(),
        )
    })
}

pub fn run_command_with_env<I, S>(
    bin: &str,
    args: I,
    current_dir: &str,
    env: &HashMap<&str, &str>,
) -> Result<(), String>
where
    I: IntoIterator<Item = S>,
    S: AsRef<OsStr>,
{
    let exit_status = Command::new(bin)
        .args(args)
        .envs(env)
        .current_dir(current_dir)
        .spawn()
        .map_err(|error| format!("Failed to spawn command `{bin}`: {error:?}"))?
        .wait()
        .map_err(|error| format!("Failed to wait command `{bin}`: {error:?}"))?;
    if exit_status.success() {
        Ok(())
    } else {
        Err(format!("Command `{bin}` failed"))
    }
}

pub fn run_command<I, S>(bin: &str, args: I, current_dir: &str) -> Result<(), String>
where
    I: IntoIterator<Item = S>,
    S: AsRef<OsStr>,
{
    run_command_with_env(bin, args, current_dir, &HashMap::new())
}

pub struct CommandOutput {
    pub output: String,
    pub exited_successfully: bool,
}

pub fn run_command_with_output_and_env<I, S>(
    bin: &str,
    args: I,
    current_dir: &str,
    env: &HashMap<&str, &str>,
) -> Result<CommandOutput, String>
where
    I: IntoIterator<Item = S>,
    S: AsRef<OsStr>,
{
    let cmd_output = Command::new(bin)
        .args(args)
        .envs(env)
        .current_dir(current_dir)
        .output()
        .map_err(|error| format!("Failed to spawn command `{bin}`: {error:?}"))?;
    let mut output = String::from_utf8_lossy(&cmd_output.stdout).into_owned();
    output.push_str(&String::from_utf8_lossy(&cmd_output.stderr));
    Ok(CommandOutput {
        output,
        exited_successfully: cmd_output.status.success(),
    })
}

pub fn run_command_with_output<I, S>(
    bin: &str,
    args: I,
    current_dir: &str,
) -> Result<CommandOutput, String>
where
    I: IntoIterator<Item = S>,
    S: AsRef<OsStr>,
{
    run_command_with_output_and_env(bin, args, current_dir, &HashMap::new())
}

#![cfg(feature = "git")]

use std::collections::HashMap;
use std::fs;
use std::path::Path;

use git2::{DiffOptions, IntoCString, Repository};

#[derive(Copy, Clone, Debug)]
pub enum LineChange {
    Added,
    RemovedAbove,
    RemovedBelow,
    Modified,
}

pub type LineChanges = HashMap<u32, LineChange>;

pub fn get_git_diff(filename: &Path) -> Option<LineChanges> {
    let repo = Repository::discover(filename).ok()?;

    let repo_path_absolute = fs::canonicalize(repo.workdir()?).ok()?;

    let filepath_absolute = fs::canonicalize(filename).ok()?;
    let filepath_relative_to_repo = filepath_absolute.strip_prefix(&repo_path_absolute).ok()?;

    let mut diff_options = DiffOptions::new();
    let pathspec = filepath_relative_to_repo.into_c_string().ok()?;
    diff_options.pathspec(pathspec);
    diff_options.context_lines(0);

    let diff = repo
        .diff_index_to_workdir(None, Some(&mut diff_options))
        .ok()?;

    let mut line_changes: LineChanges = HashMap::new();

    let mark_section =
        |line_changes: &mut LineChanges, start: u32, end: i32, change: LineChange| {
            for line in start..=end as u32 {
                line_changes.insert(line, change);
            }
        };

    let _ = diff.foreach(
        &mut |_, _| true,
        None,
        Some(&mut |delta, hunk| {
            let path = delta.new_file().path().unwrap_or_else(|| Path::new(""));

            if filepath_relative_to_repo != path {
                return false;
            }

            let old_lines = hunk.old_lines();
            let new_start = hunk.new_start();
            let new_lines = hunk.new_lines();
            let new_end = (new_start + new_lines) as i32 - 1;

            if old_lines == 0 && new_lines > 0 {
                mark_section(&mut line_changes, new_start, new_end, LineChange::Added);
            } else if new_lines == 0 && old_lines > 0 {
                if new_start == 0 {
                    mark_section(&mut line_changes, 1, 1, LineChange::RemovedAbove);
                } else {
                    mark_section(
                        &mut line_changes,
                        new_start,
                        new_start as i32,
                        LineChange::RemovedBelow,
                    );
                }
            } else {
                mark_section(&mut line_changes, new_start, new_end, LineChange::Modified);
            }

            true
        }),
        None,
    );

    Some(line_changes)
}

use rand::{Rng, RngCore, SeedableRng};
use std::sync::atomic::{AtomicUsize, Ordering};
use std::sync::Arc;
use tokio::sync::{broadcast, Notify};

use criterion::measurement::WallTime;
use criterion::{black_box, criterion_group, criterion_main, BenchmarkGroup, Criterion};

fn rt() -> tokio::runtime::Runtime {
    tokio::runtime::Builder::new_multi_thread()
        .worker_threads(6)
        .build()
        .unwrap()
}

fn do_work(rng: &mut impl RngCore) -> u32 {
    use std::fmt::Write;
    let mut message = String::new();
    for i in 1..=10 {
        let _ = write!(&mut message, " {i}={}", rng.random::<f64>());
    }
    message
        .as_bytes()
        .iter()
        .map(|&c| c as u32)
        .fold(0, u32::wrapping_add)
}

fn contention_impl<const N_TASKS: usize>(g: &mut BenchmarkGroup<WallTime>) {
    let rt = rt();

    let (tx, _rx) = broadcast::channel::<usize>(1000);
    let wg = Arc::new((AtomicUsize::new(0), Notify::new()));

    for n in 0..N_TASKS {
        let wg = wg.clone();
        let mut rx = tx.subscribe();
        let mut rng = rand::rngs::StdRng::seed_from_u64(n as u64);
        rt.spawn(async move {
            while (rx.recv().await).is_ok() {
                let r = do_work(&mut rng);
                let _ = black_box(r);
                if wg.0.fetch_sub(1, Ordering::Relaxed) == 1 {
                    wg.1.notify_one();
                }
            }
        });
    }

    const N_ITERS: usize = 100;

    g.bench_function(N_TASKS.to_string(), |b| {
        b.iter(|| {
            rt.block_on({
                let wg = wg.clone();
                let tx = tx.clone();
                async move {
                    for i in 0..N_ITERS {
                        assert_eq!(wg.0.fetch_add(N_TASKS, Ordering::Relaxed), 0);
                        tx.send(i).unwrap();
                        while wg.0.load(Ordering::Relaxed) > 0 {
                            wg.1.notified().await;
                        }
                    }
                }
            })
        })
    });
}

fn bench_contention(c: &mut Criterion) {
    let mut group = c.benchmark_group("contention");
    contention_impl::<10>(&mut group);
    contention_impl::<100>(&mut group);
    contention_impl::<500>(&mut group);
    contention_impl::<1000>(&mut group);
    group.finish();
}

criterion_group!(contention, bench_contention);

criterion_main!(contention);
